import scala.collection.mutable

def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n == 0) return 0L

  val maxNum = nums.max.toInt
  val sieve = Array.fill(maxNum + 1)(true)
  sieve(0) = false
  sieve(1) = false
  for (i <- 2 to math.sqrt(maxNum).toInt) {
    if (sieve(i)) {
      for (j <- i * i to maxNum by i) {
        sieve(j) = false
      }
    }
  }

  def getPrimeFactors(x: Int): Set[Int] = {
    if (x < 2) return Set()
    val factors = mutable.Set[Int]()
    if (x % 2 == 0) {
      factors += 2
      while (x % 2 == 0) x /= 2
    }
    var i = 3
    while (i * i <= x) {
      if (x % i == 0) {
        factors += i
        while (x % i == 0) x /= i
      }
      i += 2
    }
    if (x > 1) factors += x
    factors
  }

  val primeToIndices = mutable.HashMap[Long, List[Int]]()
  for (i <- 0 until n) {
    val x = nums(i).toInt
    val factors = getPrimeFactors(x)
    for (p <- factors) {
      val current = primeToIndices.get(p).getOrElse(List())
      primeToIndices(p) = current :+ i
    }
  }

  val dist = Array.fill(n)(Long.MaxValue)
  dist(0) = 0L
  val queue = mutable.Queue[Int](0)

  while (queue.nonEmpty) {
    val i = queue.dequeue()
    if (i == n - 1) return dist(i)
    for (dir <- List(-1, 1)) {
      val j = i + dir
      if (j >= 0 && j < n) {
        if (dist(j) > dist(i) + 1) {
          dist(j) = dist(i) + 1
          queue.enqueue(j)
        }
      }
    }
    val x = nums(i).toInt
    if (sieve(x)) {
      val p = x
      val indices = primeToIndices.get(p).getOrElse(List())
      for (j <- indices) {
        if (j != i && dist(j) > dist(i) + 1) {
          dist(j) = dist(i) + 1
          queue.enqueue(j)
        }
      }
    }
  }

  dist(n - 1)
}
